import sys

def is_palindrome(n):
    s = str(n)
    return s == s[::-1]

def main():
    N = int(sys.stdin.readline())
    max_cube = 0
    x = 1
    while True:
        cube = x ** 3
        if cube > N:
            break
        if is_palindrome(cube):
            max_cube = cube
        x += 1
    print(max_cube)

if __name__ == "__main__":
    main()
